export function maxJobFetchedTs(jobs) {
  let best = "";
  for (const job of jobs || []) {
    const ts = (job?.fetched || "").trim();
    if (!ts) continue;
    if (!best || compareDateDesc(ts, best) < 0) best = ts;
  }
  return best;
}

