function hasAtsScore(job) {
  return job?.ats_score != null && job?.ats_score !== "";
}

function matchesPin(job, pinRef, companyKey) {
  if (!pinRef || pinRef.companyKey !== companyKey) return false;
  const pinKey = (pinRef.idempotencyKey || "").trim();
  const jobKey = (job?.idempotency_key || "").trim();
  if (pinKey && jobKey && pinKey === jobKey) return true;
  return (job?.url || "").trim() === (pinRef.url || "").trim();
}

function movePinnedFirst(jobs, pinRef, companyKey) {
  if (!pinRef || !jobs.length) return jobs;
  const idx = jobs.findIndex((job) => matchesPin(job, pinRef, companyKey));
  if (idx <= 0) return jobs;
  const out = [...jobs];
  const [job] = out.splice(idx, 1);
  out.unshift(job);
  return out;
}

export function sortJobsForDisplay(jobs, opts = null) {
  const list = jobs || [];
  if (!list.length) return list;

  const scored = [];
  const unscored = [];
  for (const job of list) {
    if (hasAtsScore(job)) scored.push(job);
    else unscored.push(job);
  }

  scored.sort((a, b) => Number(b.ats_score) - Number(a.ats_score));
  const sorted = [...scored, ...unscored];
  if (!opts?.pinRef || !opts?.companyKey) return sorted;
  return movePinnedFirst(sorted, opts.pinRef, opts.companyKey);
}

