function isJobPinned(job, company, pinnedJobRef) {
  if (!pinnedJobRef || !company || !job) return false;
  const companyKey = `${company.country}:${company.name}`;
  if (pinnedJobRef.companyKey !== companyKey) return false;
  const pinKey = (pinnedJobRef.idempotencyKey || "").trim();
  const jobKey = (job.idempotency_key || "").trim();
  if (pinKey && jobKey && pinKey === jobKey) return true;
  return (job.url || "").trim() === (pinnedJobRef.url || "").trim();
}

